using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
    public byte[] RowVersion { get; set; }
}

public class Booking
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int Quantity { get; set; }
    public string CustomerEmail { get; set; }
    public DateTime BookingDate { get; set; }
}

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Booking> Bookings { get; set; }

    public EventBookingContext(DbContextOptions<EventBookingContext> options)
        : base(options)
    {
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.RowVersion)
                .IsRowVersion()
                .IsConcurrencyToken();
        });

        modelBuilder.Entity<Booking>(entity =>
        {
            entity.HasKey(b => b.Id);
        });
    }
}

public class TicketPurchaseResult
{
    public bool Success { get; set; }
    public string Message { get; set; }
    public int? BookingId { get; set; }
}

public class TicketBookingService
{
    private readonly EventBookingContext _context;
    private const int MaxRetries = 3;

    public TicketBookingService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<TicketPurchaseResult> PurchaseTicketsAsync(
        int eventId, 
        int quantity, 
        string customerEmail)
    {
        if (quantity <= 0)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero"
            };
        }

        int retryCount = 0;
        
        while (retryCount < MaxRetries)
        {
            try
            {
                var eventEntity = await _context.Events
                    .FirstOrDefaultAsync(e => e.Id == eventId);

                if (eventEntity == null)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = "Event not found"
                    };
                }

                if (eventEntity.AvailableSeats < quantity)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = $"Insufficient seats available. Only {eventEntity.AvailableSeats} seats remaining"
                    };
                }

                eventEntity.AvailableSeats -= quantity;

                var booking = new Booking
                {
                    EventId = eventId,
                    Quantity = quantity,
                    CustomerEmail = customerEmail,
                    BookingDate = DateTime.UtcNow
                };

                _context.Bookings.Add(booking);

                await _context.SaveChangesAsync();

                return new TicketPurchaseResult
                {
                    Success = true,
                    Message = "Booking completed successfully",
                    BookingId = booking.Id
                };
            }
            catch (DbUpdateConcurrencyException)
            {
                retryCount++;
                
                if (retryCount >= MaxRetries)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = "Unable to complete booking due to high demand. Please try again"
                    };
                }

                foreach (var entry in _context.ChangeTracker.Entries())
                {
                    if (entry.Entity is Event)
                    {
                        await entry.ReloadAsync();
                    }
                    else
                    {
                        entry.State = EntityState.Detached;
                    }
                }

                await Task.Delay(100 * retryCount);
            }
            catch (Exception ex)
            {
                return new TicketPurchaseResult
                {
                    Success = false,
                    Message = $"An error occurred: {ex.Message}"
                };
            }
        }

        return new TicketPurchaseResult
        {
            Success = false,
            Message = "Maximum retry attempts reached"
        };
    }

    public async Task<TicketPurchaseResult> PurchaseTicketsWithIsolationAsync(
        int eventId, 
        int quantity, 
        string customerEmail)
    {
        if (quantity <= 0)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero"
            };
        }

        using var transaction = await _context.Database.BeginTransactionAsync(
            System.Data.IsolationLevel.Serializable);

        try
        {
            var eventEntity = await _context.Events
                .FirstOrDefaultAsync(e => e.Id == eventId);

            if (eventEntity == null)
            {
                await transaction.RollbackAsync();
                return new TicketPurchaseResult
                {
                    Success = false,
                    Message = "Event not found"
                };
            }

            if (eventEntity.AvailableSeats < quantity)
            {
                await transaction.RollbackAsync();
                return new TicketPurchaseResult
                {
                    Success = false,
                    Message = $"Insufficient seats available. Only {eventEntity.AvailableSeats} seats remaining"
                };
            }

            eventEntity.AvailableSeats -= quantity;

            var booking = new Booking
            {
                EventId = eventId,
                Quantity = quantity,
                CustomerEmail = customerEmail,
                BookingDate = DateTime.UtcNow
            };

            _context.Bookings.Add(booking);

            await _context.SaveChangesAsync();
            await transaction.CommitAsync();

            return new TicketPurchaseResult
            {
                Success = true,
                Message = "Booking completed successfully",
                BookingId = booking.Id
            };
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync();
            return new TicketPurchaseResult
            {
                Success = false,
                Message = $"An error occurred: {ex.Message}"
            };
        }
    }

    public async Task<int> GetAvailableSeatsAsync(int eventId)
    {
        var eventEntity = await _context.Events
            .AsNoTracking()
            .FirstOrDefaultAsync(e => e.Id == eventId);

        return eventEntity?.AvailableSeats ?? 0;
    }
}